<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>2048</title>
<style>
  body{
    background:#121212;
    color:#eee;
    font-family:Arial,Helvetica,sans-serif;
    display:flex;flex-direction:column;align-items:center;margin:0;height:100vh;
  }
  #score{font-size:2rem;margin:20px;}
  #board{
    width:400px;height:400px;background:#333;border-radius:10px;
    display:grid;grid-template-columns:repeat(4,1fr);gap:10px;padding:10px;
  }
  .cell{
    background:#555;color:#fff;font-size:2rem;text-align:center;line-height:90px;
    border-radius:5px;
  }
  #reset{margin-top:20px;padding:10px 20px;background:#444;border:none;border-radius:5px;color:#eee;}
</style>
</head>
<body>
<div id="score">0</div>
<div id="board"></div>
<button id="reset">New Game</button>

<script>
(() => {
  const size = 4;
  let board = Array.from({length:size},()=>Array(size).fill(0));
  let scoreVal=0;

  function render(){
    const boardDiv=document.getElementById('board');
    boardDiv.innerHTML='';
    for(let r=0;r<size;r++){
      for(let c=0;c<size;c++){
        const cell=document.createElement('div');
        cell.className='cell';
        const val=board[r][c];
        if(val) cell.textContent=val;
        boardDiv.appendChild(cell);
      }
    }
    document.getElementById('score').textContent=scoreVal;
  }

  function addRandom(){
    const empties=[];
    for(let r=0;r<size;r++)for(let c=0;c<size;c++)
      if(board[r][c]===0)empties.push([r,c]);
    if(empties.length===0)return;
    const [r,c]=empties[Math.floor(Math.random()*empties.length)];
    board[r][c]=Math.random()<0.9?2:4;
  }

  function reset(){
    board=Array.from({length:size},()=>Array(size).fill(0));
    scoreVal=0;
    addRandom();addRandom();
    render();
  }

  function move(dir){
    let moved=false;
    const merged=new Array(size).fill(false);
    const delta={left:[0,-1],right:[0,1],up:[-1,0],down:[1,0]};
    const [dr,dc]=delta[dir];
    const range=dir==='right'||dir==='down'?Array.from({length:size},(_,i)=>size-1-i):Array.from({length:size},(_,i)=>i);
    for(let r of range){
      for(let c of range){
        let val=board[r][c];
        if(val===0)continue;
        let nr=r+dr,nc=c+dc;
        while(nr>=0&&nr<size&&nc>=0&&nc<size){
          const target=board[nr][nc];
          if(target===0){nr+=dr;nc+=dc;continue;}
          if(target===val && !merged[nr*size+nc]){
            board[nr][nc]*=2;
            scoreVal+=board[nr][nc];
            board[r][c]=0;
            merged[nr*size+nc]=true;
            moved=true;
          }else{
            const prevR=nr-dr,prevC=nc-dc;
            if(prevR!==r||prevC!==c){
              board[prevR][prevC]=val;
              board[r][c]=0;
              moved=true;
            }
          }
          break;
        }
      }
    }
    // After loop, shift tiles again to fill gaps
    for(let r=0;r<size;r++){
      let arr=[];
      for(let c=0;c<size;c++)if(board[r][c])arr.push(board[r][c]);
      while(arr.length<size)arr.push(0);
      for(let c=0;c<size;c++){ if(board[r][c]!==arr[c]){board[r][c]=arr[c];moved=true;} }
    }
    for(let c=0;c<size;c++){
      let arr=[];
      for(let r=0;r<size;r++)if(board[r][c])arr.push(board[r][c]);
      while(arr.length<size)arr.push(0);
      for(let r=0;r<size;r++){ if(board[r][c]!==arr[r]){board[r][c]=arr[r];moved=true;} }
    }

    if(moved)addRandom();
    render();
    return moved;
  }

  window.game={
    size,
    reset(){reset();},
    move(d){return move(d);},
    board(){return board.map(row=>row.slice());},
    setBoard(arr){
      board=arr.map(r=>r.slice());
      scoreVal=0;
      render();
    },
    score(){return scoreVal;}
  };

  document.getElementById('reset').addEventListener('click',()=>window.game.reset());

  window.addEventListener('keydown',(e)=>{
    const keys={ArrowLeft:'left',ArrowRight:'right',ArrowUp:'up',ArrowDown:'down'};
    if(keys[e.key]){ e.preventDefault(); window.game.move(keys[e.key]); }
  });

  reset();
})();
</script>
</body>
</html>
